import csv
from google_adk.tools import tool

@tool
def validate_csv_columns(file_path: str, expected_cols: list[str]) -> dict:
    """
    Validates that a CSV file contains the exact list of expected column names.

    Args:
        file_path (str): The absolute or relative path to the local CSV file.
        expected_cols (list[str]): The list of column headers required to be present.

    Returns:
        dict: A status report indicating success boolean and list of missing columns.
    """
    try:
        with open(file_path, mode='r', encoding='utf-8') as f:
            reader = csv.reader(f)
            headers = next(reader, None)
            if not headers:
                return {"status": "error", "valid": False, "reason": "CSV is empty"}

            missing = [col for col in expected_cols if col not in headers]
            if missing:
                return {"status": "invalid", "valid": False, "missing": missing}
            return {"status": "success", "valid": true, "missing": []}
    except Exception as e:
        return {"status": "error", "valid": False, "reason": str(e)}
